################################################################################
# ECS Cluster
################################################################################

resource "aws_ecs_cluster" "main" {
  name = local.name_prefix

  setting {
    name  = "containerInsights"
    value = "enabled"
  }
}

################################################################################
# AMI
################################################################################

data "aws_ssm_parameter" "ecs_ami_arm64" {
  name = "/aws/service/ecs/optimized-ami/amazon-linux-2023/arm64/recommended/image_id"
}

data "aws_ssm_parameter" "ecs_ami_x86" {
  name = "/aws/service/ecs/optimized-ami/amazon-linux-2023/recommended/image_id"
}

################################################################################
# ClickHouse EC2 (r6gd.4xlarge - ARM64 with NVMe)
################################################################################

locals {
  clickhouse_nodes = {
    "s1r1" = { shard = "01", replica = "clickhouse-shard1-replica1", az_index = 0 }
    "s1r2" = { shard = "01", replica = "clickhouse-shard1-replica2", az_index = 1 }
    "s2r1" = { shard = "02", replica = "clickhouse-shard2-replica1", az_index = 0 }
    "s2r2" = { shard = "02", replica = "clickhouse-shard2-replica2", az_index = 1 }
  }

  private_subnet_ids = module.vpc.private_subnets
}

resource "aws_launch_template" "clickhouse" {
  for_each = local.clickhouse_nodes

  name_prefix   = "${local.name_prefix}-ch-${each.key}-"
  image_id      = data.aws_ssm_parameter.ecs_ami_arm64.value
  instance_type = var.clickhouse_instance_type

  iam_instance_profile {
    name = aws_iam_instance_profile.ec2.name
  }

  vpc_security_group_ids = [aws_security_group.clickhouse.id]

  user_data = base64encode(templatefile("${path.module}/templates/clickhouse_user_data.sh", {
    cluster_name   = aws_ecs_cluster.main.name
    node_attribute = "clickhouse_node"
    node_value     = each.key
  }))

  tag_specifications {
    resource_type = "instance"
    tags = merge(local.common_tags, {
      Name            = "${local.name_prefix}-ch-${each.key}"
      ClickHouseNode  = each.key
      ClickHouseShard = each.value.shard
    })
  }

  lifecycle { create_before_destroy = true }
}

resource "aws_autoscaling_group" "clickhouse" {
  for_each = local.clickhouse_nodes

  name                  = "${local.name_prefix}-ch-${each.key}"
  min_size              = 1
  max_size              = 1
  desired_capacity      = 1
  protect_from_scale_in = true
  vpc_zone_identifier   = [local.private_subnet_ids[each.value.az_index % length(local.private_subnet_ids)]]

  launch_template {
    id      = aws_launch_template.clickhouse[each.key].id
    version = aws_launch_template.clickhouse[each.key].latest_version
  }

  tag {
    key                 = "AmazonECSManaged"
    value               = true
    propagate_at_launch = true
  }

  dynamic "tag" {
    for_each = local.common_tags
    content {
      key                 = tag.key
      value               = tag.value
      propagate_at_launch = true
    }
  }
}

################################################################################
# Keeper EC2 (t3.medium - x86_64)
################################################################################

resource "aws_launch_template" "keeper" {
  for_each = local.keeper_nodes

  name_prefix   = "${local.name_prefix}-keeper-${each.key}-"
  image_id      = data.aws_ssm_parameter.ecs_ami_x86.value
  instance_type = var.keeper_instance_type

  iam_instance_profile {
    name = aws_iam_instance_profile.ec2.name
  }

  vpc_security_group_ids = [aws_security_group.keeper.id]

  user_data = base64encode(templatefile("${path.module}/templates/keeper_user_data.sh", {
    cluster_name   = aws_ecs_cluster.main.name
    node_attribute = "keeper_node"
    node_value     = each.key
    ebs_volume_id  = aws_ebs_volume.keeper[each.key].id
  }))

  tag_specifications {
    resource_type = "instance"
    tags = merge(local.common_tags, {
      Name       = "${local.name_prefix}-keeper-${each.key}"
      KeeperNode = each.key
    })
  }

  lifecycle { create_before_destroy = true }
}

resource "aws_ebs_volume" "keeper" {
  for_each = local.keeper_nodes

  availability_zone = var.availability_zones[index(keys(local.keeper_nodes), each.key) % length(var.availability_zones)]
  size              = 20
  type              = "gp3"
  iops              = 3000
  throughput        = 125
  encrypted         = true

  tags = merge(local.common_tags, {
    Name       = "${local.name_prefix}-keeper-${each.key}-data"
    KeeperNode = each.key
  })

  # lifecycle { prevent_destroy = true }
}

resource "aws_autoscaling_group" "keeper" {
  for_each = local.keeper_nodes

  name                  = "${local.name_prefix}-keeper-${each.key}"
  min_size              = 1
  max_size              = 1
  desired_capacity      = 1
  protect_from_scale_in = true
  vpc_zone_identifier   = [local.private_subnet_ids[index(keys(local.keeper_nodes), each.key) % length(local.private_subnet_ids)]]

  launch_template {
    id      = aws_launch_template.keeper[each.key].id
    version = aws_launch_template.keeper[each.key].latest_version
  }

  tag {
    key                 = "AmazonECSManaged"
    value               = true
    propagate_at_launch = true
  }

  dynamic "tag" {
    for_each = local.common_tags
    content {
      key                 = tag.key
      value               = tag.value
      propagate_at_launch = true
    }
  }
}

################################################################################
# Capacity Providers
################################################################################

resource "aws_ecs_capacity_provider" "clickhouse" {
  for_each = local.clickhouse_nodes

  name = "${local.name_prefix}-ch-${each.key}"

  auto_scaling_group_provider {
    auto_scaling_group_arn         = aws_autoscaling_group.clickhouse[each.key].arn
    managed_termination_protection = "ENABLED"

    managed_scaling {
      status          = "ENABLED"
      target_capacity = 100
    }
  }
}

resource "aws_ecs_capacity_provider" "keeper" {
  for_each = local.keeper_nodes

  name = "${local.name_prefix}-keeper-${each.key}"

  auto_scaling_group_provider {
    auto_scaling_group_arn         = aws_autoscaling_group.keeper[each.key].arn
    managed_termination_protection = "ENABLED"

    managed_scaling {
      status          = "ENABLED"
      target_capacity = 100
    }
  }
}

resource "aws_ecs_cluster_capacity_providers" "main" {
  cluster_name = aws_ecs_cluster.main.name

  capacity_providers = concat(
    [for k, v in aws_ecs_capacity_provider.clickhouse : v.name],
    [for v in aws_ecs_capacity_provider.keeper : v.name],
  )
}

################################################################################
# ClickHouse - CloudWatch Log Group
################################################################################

resource "aws_cloudwatch_log_group" "clickhouse" {
  name              = "/ecs/${local.name_prefix}/clickhouse"
  retention_in_days = 30
}

################################################################################
# ClickHouse - Secrets Manager
################################################################################

resource "aws_kms_key" "clickhouse_secrets" {
  description         = "KMS key for ClickHouse Secrets Manager"
  enable_key_rotation = true
  policy              = data.aws_iam_policy_document.clickhouse_kms_policy.json
}

data "aws_iam_policy_document" "clickhouse_kms_policy" {
  statement {
    sid    = "AllowRootAdmin"
    effect = "Allow"
    principals {
      type        = "AWS"
      identifiers = ["arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"]
    }
    actions   = ["kms:*"]
    resources = ["*"]
  }
  statement {
    sid    = "AllowECSTaskExecutionDecrypt"
    effect = "Allow"
    principals {
      type        = "AWS"
      identifiers = [aws_iam_role.ecs_task_execution.arn]
    }
    actions   = ["kms:Decrypt", "kms:DescribeKey"]
    resources = ["*"]
  }
}

resource "aws_kms_alias" "clickhouse_secrets" {
  name          = "alias/${local.name_prefix}-clickhouse-secrets"
  target_key_id = aws_kms_key.clickhouse_secrets.key_id
}

resource "random_string" "suffix" {
  length  = 8
  upper   = false
  special = false
}

resource "aws_secretsmanager_secret" "clickhouse_credentials" {
  name        = "${var.project}/${var.environment}/clickhouse-credentials-${random_string.suffix.result}"
  description = "ClickHouse user credentials"
  kms_key_id  = aws_kms_key.clickhouse_secrets.arn
}

resource "aws_secretsmanager_secret_version" "clickhouse_credentials" {
  secret_id = aws_secretsmanager_secret.clickhouse_credentials.id
  secret_string = jsonencode({
    default_password  = var.clickhouse_default_password
    readonly_password = var.clickhouse_readonly_password
  })
}

################################################################################
# ClickHouse - Locals
################################################################################

locals {
  ch_fqdns = {
    "s1r1" = "clickhouse-shard1-replica1.${var.project}.local"
    "s1r2" = "clickhouse-shard1-replica2.${var.project}.local"
    "s2r1" = "clickhouse-shard2-replica1.${var.project}.local"
    "s2r2" = "clickhouse-shard2-replica2.${var.project}.local"
  }

  s3_endpoint = "https://s3.${var.aws_region}.amazonaws.com/${aws_s3_bucket.data.id}/clickhouse/"
}

################################################################################
# ClickHouse - Task Definitions
################################################################################

resource "aws_ecs_task_definition" "clickhouse" {
  for_each = local.clickhouse_nodes

  family                   = "${local.name_prefix}-ch-${each.key}"
  requires_compatibilities = ["EC2"]
  network_mode             = "awsvpc"
  cpu                      = var.clickhouse_cpu
  memory                   = var.clickhouse_memory
  execution_role_arn       = aws_iam_role.ecs_task_execution.arn
  task_role_arn            = aws_iam_role.ecs_task.arn

  volume {
    name      = "s3cache"
    host_path = "/var/lib/clickhouse/s3cache"
  }

  container_definitions = jsonencode([{
    name      = "clickhouse"
    image     = "${aws_ecr_repository.repos["clickhouse"].repository_url}:latest"
    essential = true

    portMappings = [
      { containerPort = 8123, protocol = "tcp" },
      { containerPort = 9000, protocol = "tcp" },
      { containerPort = 9009, protocol = "tcp" },
      { containerPort = 9363, protocol = "tcp" },
    ]

    mountPoints = [{
      sourceVolume  = "s3cache"
      containerPath = "/var/lib/clickhouse/s3cache"
      readOnly      = false
    }]

    environment = [
      { name = "CH_SHARD", value = each.value.shard },
      { name = "CH_REPLICA", value = each.value.replica },
      { name = "CH_S3_ENDPOINT", value = local.s3_endpoint },
      { name = "CH_SHARD1_REPLICA1_HOST", value = local.ch_fqdns["s1r1"] },
      { name = "CH_SHARD1_REPLICA2_HOST", value = local.ch_fqdns["s1r2"] },
      { name = "CH_SHARD2_REPLICA1_HOST", value = local.ch_fqdns["s2r1"] },
      { name = "CH_SHARD2_REPLICA2_HOST", value = local.ch_fqdns["s2r2"] },
      { name = "CH_KEEPER_HOST_1", value = local.keeper_fqdns["1"] },
      { name = "CH_KEEPER_HOST_2", value = local.keeper_fqdns["2"] },
      { name = "CH_KEEPER_HOST_3", value = local.keeper_fqdns["3"] },
      { name = "CH_ALLOWED_NETWORKS", value = var.vpc_cidr },
    ]

    secrets = [
      {
        name      = "CH_DEFAULT_PASSWORD"
        valueFrom = "${aws_secretsmanager_secret.clickhouse_credentials.arn}:default_password::"
      },
      {
        name      = "CH_READONLY_PASSWORD"
        valueFrom = "${aws_secretsmanager_secret.clickhouse_credentials.arn}:readonly_password::"
      },
    ]

    logConfiguration = {
      logDriver = "awslogs"
      options = {
        "awslogs-group"         = aws_cloudwatch_log_group.clickhouse.name
        "awslogs-region"        = data.aws_region.current.name
        "awslogs-stream-prefix" = "ch-${each.key}"
      }
    }

    healthCheck = {
      command     = ["CMD-SHELL", "wget --no-verbose --tries=1 --spider http://localhost:8123/ping || exit 1"]
      interval    = 30
      timeout     = 5
      retries     = 3
      startPeriod = 60
    }
  }])
}

################################################################################
# ClickHouse - Service Discovery
################################################################################

resource "aws_service_discovery_service" "clickhouse" {
  for_each = local.clickhouse_nodes

  name = each.value.replica

  dns_config {
    namespace_id = aws_service_discovery_private_dns_namespace.main.id

    dns_records {
      ttl  = 10
      type = "A"
    }

    routing_policy = "MULTIVALUE"
  }

  health_check_custom_config {
    failure_threshold = 1
  }
}

################################################################################
# ClickHouse - ECS Services
################################################################################

resource "aws_ecs_service" "clickhouse" {
  for_each = local.clickhouse_nodes

  name            = "${local.name_prefix}-ch-${each.key}"
  cluster         = aws_ecs_cluster.main.id
  task_definition = aws_ecs_task_definition.clickhouse[each.key].arn
  desired_count   = 1

  deployment_minimum_healthy_percent = 0
  deployment_maximum_percent         = 100
  health_check_grace_period_seconds  = 300

  network_configuration {
    subnets         = local.private_subnet_ids
    security_groups = [aws_security_group.clickhouse.id]
  }

  service_registries {
    registry_arn = aws_service_discovery_service.clickhouse[each.key].arn
  }

  capacity_provider_strategy {
    capacity_provider = "${local.name_prefix}-ch-${each.key}"
    weight            = 1
    base              = 1
  }

  load_balancer {
    target_group_arn = aws_lb_target_group.ch_http.arn
    container_name   = "clickhouse"
    container_port   = 8123
  }

  placement_constraints {
    type       = "memberOf"
    expression = "attribute:clickhouse_node == ${each.key}"
  }

  depends_on = [aws_ecs_capacity_provider.clickhouse, aws_ecs_cluster_capacity_providers.main, aws_ecs_service.keeper]
}

################################################################################
# Keeper - CloudWatch Log Group
################################################################################

resource "aws_cloudwatch_log_group" "keeper" {
  name              = "/ecs/${local.name_prefix}/keeper"
  retention_in_days = 30
}

################################################################################
# Keeper - Locals
################################################################################

locals {
  keeper_nodes = { "1" = {}, "2" = {}, "3" = {} }

  keeper_fqdns = {
    "1" = "keeper-1.${var.project}.local"
    "2" = "keeper-2.${var.project}.local"
    "3" = "keeper-3.${var.project}.local"
  }
}

################################################################################
# Keeper - Task Definitions
################################################################################

resource "aws_ecs_task_definition" "keeper" {
  for_each = local.keeper_nodes

  family                   = "${local.name_prefix}-keeper-${each.key}"
  requires_compatibilities = ["EC2"]
  network_mode             = "awsvpc"
  cpu                      = var.keeper_cpu
  memory                   = var.keeper_memory
  execution_role_arn       = aws_iam_role.ecs_task_execution.arn
  task_role_arn            = aws_iam_role.ecs_task_keeper.arn

  volume {
    name      = "keeper-data"
    host_path = "/mnt/keeper-data"
  }

  container_definitions = jsonencode([{
    name      = "keeper"
    image     = "${aws_ecr_repository.repos["clickhouse-keeper"].repository_url}:latest"
    essential = true

    portMappings = [
      { containerPort = 9181, protocol = "tcp" },
      { containerPort = 9234, protocol = "tcp" },
    ]

    mountPoints = [
      {
        sourceVolume  = "keeper-data"
        containerPath = "/var/lib/clickhouse/coordination"
        readOnly      = false
      },
    ]

    environment = [
      { name = "KEEPER_SERVER_ID", value = each.key },
      { name = "KEEPER_HOST_1", value = local.keeper_fqdns["1"] },
      { name = "KEEPER_HOST_2", value = local.keeper_fqdns["2"] },
      { name = "KEEPER_HOST_3", value = local.keeper_fqdns["3"] },
    ]

    logConfiguration = {
      logDriver = "awslogs"
      options = {
        "awslogs-group"         = aws_cloudwatch_log_group.keeper.name
        "awslogs-region"        = data.aws_region.current.name
        "awslogs-stream-prefix" = "keeper-${each.key}"
      }
    }

    healthCheck = {
      command     = ["CMD-SHELL", "echo ruok | nc localhost 9181 | grep -q imok"]
      interval    = 10
      timeout     = 5
      retries     = 3
      startPeriod = 30
    }
  }])
}

################################################################################
# Keeper - Service Discovery
################################################################################

resource "aws_service_discovery_service" "keeper" {
  for_each = local.keeper_nodes

  name = "keeper-${each.key}"

  dns_config {
    namespace_id = aws_service_discovery_private_dns_namespace.main.id

    dns_records {
      ttl  = 10
      type = "A"
    }

    routing_policy = "MULTIVALUE"
  }

  health_check_custom_config {
    failure_threshold = 1
  }
}

################################################################################
# Keeper - ECS Services
################################################################################

resource "aws_ecs_service" "keeper" {
  for_each = local.keeper_nodes

  name            = "${local.name_prefix}-keeper-${each.key}"
  cluster         = aws_ecs_cluster.main.id
  task_definition = aws_ecs_task_definition.keeper[each.key].arn
  desired_count   = 1

  deployment_minimum_healthy_percent = 0
  deployment_maximum_percent         = 100

  network_configuration {
    subnets         = local.private_subnet_ids
    security_groups = [aws_security_group.keeper.id]
  }

  service_registries {
    registry_arn = aws_service_discovery_service.keeper[each.key].arn
  }

  capacity_provider_strategy {
    capacity_provider = "${local.name_prefix}-keeper-${each.key}"
    weight            = 1
    base              = 1
  }

  placement_constraints {
    type       = "memberOf"
    expression = "attribute:keeper_node == ${each.key}"
  }

  depends_on = [aws_ecs_capacity_provider.keeper, aws_ecs_cluster_capacity_providers.main]
}

